  aspect-ratio: 1;
  border-radius: 16px;
  display: grid;
  place-items: center;
  font-size: clamp(1.3rem, 4vw, 2rem);
  font-weight: 800;
  background: rgba(255, 255, 255, 0.12);
  color: #0f172a;
}

.cell-empty {
  background: rgba(255, 255, 255, 0.16);
}

